    case 'wardrobe':
      return '#d2b48c';
    case 'lamp':
      return '#facc15';
    case 'rug':
      return '#94a3b8';
    case 'counter':
      return paint?.categories.floor.color ?? '#cfc9be';
    case 'sofa':
