  ],
};

const placedFridge: Extract<Element, { kind: 'placed_asset' }> = {
  kind: 'placed_asset',
  id: 'pa-fridge',
  name: 'Kitchen fridge',
  assetId: 'asset-fridge',
  levelId: 'lvl',
