function addBox(
  group: THREE.Group,
  pickId: string,
  size: [number, number, number],
  pos: [number, number, number],
  color: string,
  roughness?: number,
  metalness?: number,
): THREE.Mesh {
  const mesh = new THREE.Mesh(
    new THREE.BoxGeometry(...size),
    meshMaterial(color, roughness, metalness),
  );
  mesh.position.set(...pos);
  mesh.userData.bimPickId = pickId;
  addEdges(mesh);
  group.add(mesh);
  return mesh;
}

function addCylinder(
  group: THREE.Group,
  pickId: string,
  radius: number,
  height: number,
  pos: [number, number, number],
  color: string,
): THREE.Mesh {
  const mesh = new THREE.Mesh(
