                          onClick={() => void submitUpdate(l.id, { sourceModelRevision: null })}
                          className="rounded border border-border px-2 py-0.5 text-[11px] hover:bg-surface-strong disabled:opacity-50"
                        >
                          Follow latest
                        </button>
                      ) : (
                        <button
