                          disabled={pending || typeof currentSrcRev !== 'number'}
                          data-testid={`manage-links-pin-${l.id}`}
                          onClick={() =>
                            void submitUpdate(l.id, {
                              sourceModelRevision: currentSrcRev ?? 0,
                            })
